import sys
import os
import re

# Target file
template_path = "/src/bad/templates/posts.view.html"

def has_csrf_token(form_content):
    """Check if the given form HTML contains a Django CSRF token."""
    return bool(re.search(r'{%\s*csrf_token\s*%}', form_content))

def extract_forms(content):
    """Yield each <form ...>...</form> block from the template."""
    # Simple regex to capture form blocks (non-greedy)
    pattern = re.compile(r'(<form\b[^>]*>.*?</form>)', re.DOTALL | re.IGNORECASE)
    return pattern.findall(content)

def main():
    try:
        with open(template_path, 'r', encoding='utf-8') as f:
            tmpl = f.read()
    except Exception as e:
        print(f"VALIDATION_ERROR: Could not read file: {e}")
        sys.exit(1)

    vulnerable = False

    for form_block in extract_forms(tmpl):
        # Check if form uses POST method
        if re.search(r'<form[^>]*\bmethod=["\']?post["\']?', form_block, re.IGNORECASE):
            if not has_csrf_token(form_block):
                vulnerable = True
                break

    if vulnerable:
        print("VALIDATION_SUCCESS: POST form without {% csrf_token %} detected.")
        sys.exit(0)
    else:
        print("VALIDATION_FAILURE: No missing CSRF token found.")
        sys.exit(1)

