import sys
import os

# Aurix Red validation script for avoid_using_app_run_directly
# Checks that Flask's app.run(...) is invoked at top-level without an __main__ guard.

source_file = "/src/bad/vulpy-ssl.py"

def main():
    try:
        with open(source_file, "r", encoding="utf-8") as f:
            lines = f.readlines()
    except Exception:
        sys.exit(1)  # Unable to read target file

    # Locate lines containing app.run
    run_lines = [i for i, line in enumerate(lines) if "app.run" in line]

    if not run_lines:
        # No app.run found → not applicable
        sys.exit(1)

    # Determine if any app.run is protected by an if __name__ == "__main__" guard
    guarded = False
    for idx in run_lines:
        # Scan upwards for a guard line before the current line
        for j in range(idx - 1, -1, -1):
            stripped = lines[j].strip()
            if stripped.startswith("if __name__") and ("__main__" in stripped):
                # Simple heuristic: if the guard line is less indented than app.run, assume protection
                guard_indent = len(lines[j]) - len(lines[j].lstrip())
                run_indent = len(lines[idx]) - len(lines[idx].lstrip())
                if guard_indent < run_indent:
                    guarded = True
                break
            # Stop scanning if we hit a blank line or a top‑level statement
            if stripped == "" or not stripped.startswith((" ", "\t")):
                break

    # Vulnerable if app.run exists and is NOT guarded
    if not guarded:
        print("VALIDATION_SUCCESS: app.run is invoked at top level without guard.")
        sys.exit(0)
    else:
        sys.exit(1)

if __name__ == "__main__":
    main()

