import os
import sys

# Path to the vulnerable source file
source_path = "/src/bad/vulpy-ssl.py"

def read_file(path):
    with open(path, "r", encoding="utf-8") as f:
        return f.readlines()

def write_file(path, lines):
    with open(path, "w", encoding="utf-8") as f:
        f.writelines(lines)

def is_guarded(lines, run_idx):
    """
    Return True if the app.run line at run_idx is already protected by an
    `if __name__ == "__main__":` block.
    """
    # Scan upwards looking for a guard line that is less indented
    run_indent = len(lines[run_idx]) - len(lines[run_idx].lstrip())
    for i in range(run_idx - 1, -1, -1):
        stripped = lines[i].strip()
        if stripped.startswith("if __name__") and "__main__" in stripped:
            guard_indent = len(lines[i]) - len(lines[i].lstrip())
            if guard_indent < run_indent:
                return True
        # Stop if we encounter a top‑level statement or a blank line
        if stripped == "" or not stripped.startswith((" ", "\t")):
            break
    return False

def guard_app_run(lines):
    """
    Locate the first unguarded `app.run` call and wrap it in a
    `if __name__ == "__main__":` block, preserving original indentation.
    """
    for idx, line in enumerate(lines):
        if "app.run" in line:
            if is_guarded(lines, idx):
                # Already safe – nothing to do
                return None
            # Determine original indentation
            indent = line[:len(line) - len(line.lstrip())]
            # Build guarded block
            guarded_block = [
                f"{indent}if __name__ == \"__main__\":\n",
                f"{indent}    {line.lstrip()}"
            ]
            # Replace the original line with the guarded block
            new_lines = lines[:idx] + guarded_block + lines[idx+1:]
            return new_lines
    return None  # No app.run found

def main():
    try:
        original_lines = read_file(source_path)
    except Exception as e:
        print(f"PATCH_ERROR: Unable to read {source_path} – {e}")
        sys.exit(1)

    patched = guard_app_run(original_lines)
    if patched is None:
        print("PATCH_SKIPPED: No unguarded app.run() call found.")
        sys.exit(0)

    try:
        write_file(source_path, patched)
        print("PATCH_APPLIED: app.run() is now protected by __main__ guard.")
    except Exception as e:
        print(f"PATCH_ERROR: Unable to write {source_path} – {e}")
        sys.exit(1)

if __name__ == "__main__":
    main()

