import ast

source_file = "/src/good/libuser.py"

def is_vulnerable_node(node):
    # Look for calls to cursor.execute (or any .execute) with a formatted string
    if isinstance(node, ast.Call):
        # function could be attribute like c.execute
        if isinstance(node.func, ast.Attribute) and node.func.attr == "execute":
            # Check first argument
            if node.args:
                arg = node.args[0]
                # Detect string formatting using % operator
                if isinstance(arg, ast.BinOp) and isinstance(arg.op, ast.Mod):
                    # This is a classic "%s" % var or "..." % (var1, var2) pattern
                    return True
                # Detect f-string or .format usage (still unsafe if contains user data)
                if isinstance(arg, ast.JoinedStr):
                    return True
                if isinstance(arg, ast.Call) and isinstance(arg.func, ast.Attribute):
                    if arg.func.attr == "format":
                        return True
    return False

def main():
    try:
        with open(source_file, "r", encoding="utf-8") as f:
            tree = ast.parse(f.read(), filename=source_file)
    except Exception as e:
        print(f"VALIDATION_ERROR: Cannot parse source file: {e}")
        sys.exit(1)

    vulnerable = False
    for node in ast.walk(tree):
        if is_vulnerable_node(node):
            vulnerable = True
            break

    if vulnerable:
        print("VALIDATION_SUCCESS: Detected raw SQL execution with string formatting (potential SQL injection).")
        sys.exit(0)
    else:
        print("VALIDATION_FAILURE: No unsafe raw SQL execution patterns found.")
        sys.exit(1)

if __name__ == "__main__":
    main()

